use crate::mmio;

pub const ARCH: &str = "riscv64";
pub const UART0: usize = 0x1000_0000;
#[allow(dead_code)]
pub const VIRTIO0: usize = 0x1000_1000;

const UART_THR: usize = 0;
const UART_LSR: usize = 5;
const UART_LSR_THR_EMPTY: u8 = 0x20;
const UART_PUTCHAR_SPINS: usize = 1_000_000;
const TEST_FINISHER: usize = 0x0010_0000;
const TEST_FINISHER_PASS: u32 = 0x5555;
const TEST_FINISHER_FAIL: u32 = 0x3333;
const SBI_EXT_SYSTEM_RESET: usize = 0x5352_5354;
const SBI_FUNC_SYSTEM_RESET: usize = 0;
const SBI_EXT_TIME: usize = 0x5449_4d45;
const SBI_FUNC_SET_TIMER: usize = 0;
const SBI_RESET_TYPE_SHUTDOWN: usize = 0;
const SBI_RESET_REASON_NONE: usize = 0;
const SBI_RESET_REASON_SYSTEM_FAILURE: usize = 1;
const SSTATUS_SIE: usize = 1 << 1;
const SSTATUS_SPP: usize = 1 << 8;
const SSTATUS_SPIE: usize = 1 << 5;
const SCAUSE_USER_ECALL: usize = 8;
const SCAUSE_INTERRUPT: usize = 1usize << (usize::BITS as usize - 1);
const SCAUSE_SUPERVISOR_TIMER: usize = SCAUSE_INTERRUPT | 5;
const SIE_STIE: usize = 1 << 5;
const SIP_STIP: usize = 1 << 5;
/// Budget tick = 100 ms wall (QEMU RISC-V virt timebase 10 MHz × 1_000_000
/// units). This is the historically-proven scheduling tick — do not retune it
/// for budget reasons; the wall-clock bound comes from the run tick budget
/// (`BUDGET_TICKS_PER_SECOND` × profile seconds), not from the tick size.
const USER_BUDGET_TIMER_TICKS: u64 = 1_000_000;
/// Budget ticks per wall second (10 MHz / 1_000_000-unit tick = 10/s), used to
/// convert the profile's seconds-denominated run budget into tick counts.
pub const BUDGET_TICKS_PER_SECOND: usize = 10;
/// Process rotation happens on every Nth budget tick. Every tick charges the
/// run's wall budget, but the expensive switch path (process-image snapshot
/// copies) and the per-process event charge run only at the historical
/// ~100 ms cadence — which IS the tick period here, so N = 1.
pub const TICKS_PER_ROTATION: usize = 1;

#[repr(C)]
#[derive(Clone, Copy)]
pub struct TrapFrame {
    pub regs: [usize; 32],
    pub sepc: usize,
    pub sstatus: usize,
    pub scause: usize,
    pub stval: usize,
}

impl TrapFrame {
    pub const fn new() -> Self {
        Self {
            regs: [0; 32],
            sepc: 0,
            sstatus: 0,
            scause: 0,
            stval: 0,
        }
    }

    pub fn trap_pc(&self) -> usize {
        self.sepc
    }

    pub fn trap_cause(&self) -> usize {
        self.scause
    }

    pub fn trap_value(&self) -> usize {
        self.stval
    }

    pub fn syscall_args(&self) -> [usize; 6] {
        [
            self.regs[10],
            self.regs[11],
            self.regs[12],
            self.regs[13],
            self.regs[14],
            self.regs[15],
        ]
    }

    pub fn syscall_nr(&self) -> usize {
        self.regs[17]
    }

    pub fn set_syscall_result(&mut self, result: isize) {
        self.regs[10] = result as usize;
    }

    pub fn set_user_stack(&mut self, stack: usize) {
        self.regs[2] = stack;
    }

    /// User program counter (sepc).
    pub fn program_counter(&self) -> usize {
        self.sepc
    }

    pub fn set_program_counter(&mut self, pc: usize) {
        self.sepc = pc;
    }

    /// First argument register (a0) — set to the signal number on delivery.
    pub fn set_arg0(&mut self, value: usize) {
        self.regs[10] = value;
    }

    /// Return-address register (ra) — set to the sa_restorer on delivery so the
    /// handler returns into the rt_sigreturn trampoline.
    pub fn set_return_address(&mut self, ra: usize) {
        self.regs[1] = ra;
    }

    /// True if `sret` from this frame resumes user mode (SPP=0). Becomes false
    /// once `prepare_user_return` flips it to supervisor (the run is ending),
    /// which is the guard that stops signal delivery on a terminating return.
    pub fn returns_to_user(&self) -> bool {
        self.sstatus & SSTATUS_SPP == 0
    }

    /// Force this frame to resume in U-mode (SPP=0). `rt_sigreturn` restores a
    /// TrapFrame from fully user-controlled memory; without this a forged frame
    /// with SPP=1 would `sret` into supervisor mode at a user-chosen PC
    /// (privilege escalation). A legitimate signal frame already has SPP=0 (the
    /// interrupted code was user-mode), so this is a no-op for real returns.
    pub fn sanitize_user_privilege(&mut self) {
        self.sstatus &= !SSTATUS_SPP;
    }

    pub fn reset_for_exec(&mut self, entry: usize, stack: usize, user_tp: usize) {
        let sstatus = (self.sstatus & !(SSTATUS_SPP | SSTATUS_SIE)) | SSTATUS_SPIE;
        *self = Self::new();
        self.regs[2] = stack;
        self.regs[4] = user_tp;
        self.sepc = entry;
        self.sstatus = sstatus;
    }
}

extern "C" {
    fn __riscv_trap_vector();
    fn __riscv_enter_user(frame: *const TrapFrame) -> isize;
    static __riscv_return_ra: usize;
    static __riscv_return_sp: usize;
    static __riscv_return_gp: usize;
    static __riscv_return_tp: usize;
    static __riscv_return_s: [usize; 12];
}

pub fn putchar(byte: u8) {
    for _ in 0..UART_PUTCHAR_SPINS {
        if unsafe { mmio::read8(UART0 + UART_LSR) } & UART_LSR_THR_EMPTY != 0 {
            unsafe {
                mmio::write8(UART0 + UART_THR, byte);
            }
            return;
        }
        core::hint::spin_loop();
    }
}

pub fn shutdown_success() {
    unsafe {
        sbi_system_reset(SBI_RESET_TYPE_SHUTDOWN, SBI_RESET_REASON_NONE);
        mmio::write32(TEST_FINISHER, TEST_FINISHER_PASS);
    }
}

pub fn shutdown_failure() {
    unsafe {
        sbi_system_reset(SBI_RESET_TYPE_SHUTDOWN, SBI_RESET_REASON_SYSTEM_FAILURE);
        mmio::write32(TEST_FINISHER, TEST_FINISHER_FAIL);
    }
}

pub fn halt() {
    unsafe {
        core::arch::asm!("wfi", options(nomem, nostack));
    }
}

pub fn install_trap_vector() {
    unsafe {
        core::arch::asm!(
            "csrw stvec, {trap}",
            trap = in(reg) __riscv_trap_vector as usize,
            options(nostack)
        );
    }
}

pub fn enable_user_budget_timer() {
    unsafe {
        set_sie_bits(SIE_STIE);

        set_sie_bits(SIE_STIE);
        schedule_user_budget_timer();
    }
}

pub fn schedule_user_budget_timer() {
    unsafe {
        let deadline = read_time().wrapping_add(USER_BUDGET_TIMER_TICKS);
        write_stimecmp(deadline);
        sbi_set_timer(deadline);
    }
}

pub fn disable_user_budget_timer() {
    unsafe {
        clear_sie_bits(SIE_STIE);
        write_stimecmp(u64::MAX);
    }
}

pub fn is_user_budget_timer_interrupt(frame: &TrapFrame) -> bool {
    frame.scause == SCAUSE_SUPERVISOR_TIMER
}

pub fn is_budget_timer_interrupt(frame: &TrapFrame) -> bool {
    is_user_budget_timer_interrupt(frame)
}

pub fn acknowledge_user_budget_timer() {
    schedule_user_budget_timer();
}

/// One-shot boot probe: does the budget timer demonstrably fire on this
/// machine? Arms a ~1 ms deadline with the timer interrupt MASKED in `sie` and
/// watches the `sip.STIP` pending bit only — no interrupt is ever taken.
/// Bounded by both an rdtime deadline (~50 ms) and a spin cap, so the probe
/// itself can never hang even if the counter is broken.
pub fn probe_budget_timer_alive() -> bool {
    const PROBE_DELAY: u64 = 10_000; // 1 ms @ 10 MHz timebase
    const PROBE_DEADLINE: u64 = 500_000; // 50 ms @ 10 MHz timebase
    const PROBE_SPIN_CAP: usize = 50_000_000;
    unsafe {
        clear_sie_bits(SIE_STIE);
        let start = read_time();
        let deadline = start.wrapping_add(PROBE_DELAY);
        write_stimecmp(deadline);
        sbi_set_timer(deadline);
        let mut alive = false;
        for _ in 0..PROBE_SPIN_CAP {
            if read_sip() & SIP_STIP != 0 {
                alive = true;
                break;
            }
            if read_time().wrapping_sub(start) > PROBE_DEADLINE {
                break;
            }
            core::hint::spin_loop();
        }
        write_stimecmp(u64::MAX);
        sbi_set_timer(u64::MAX);
        alive
    }
}

pub unsafe fn enter_user(entry: usize, stack: usize, arg0: usize, user_tp: usize) -> isize {
    let mut frame = TrapFrame::new();
    frame.regs[2] = stack;
    frame.regs[4] = user_tp;
    frame.regs[10] = arg0;
    frame.sepc = entry;
    let sstatus = read_sstatus();
    frame.sstatus = (sstatus & !(SSTATUS_SPP | SSTATUS_SIE)) | SSTATUS_SPIE;
    __riscv_enter_user(&frame)
}

pub unsafe fn prepare_user_return(frame: &mut TrapFrame, code: isize) {
    frame.sepc = __riscv_return_ra;
    frame.sstatus = (frame.sstatus & !(SSTATUS_SIE | SSTATUS_SPIE)) | SSTATUS_SPP;
    frame.regs[1] = 0;
    frame.regs[2] = __riscv_return_sp;
    frame.regs[3] = __riscv_return_gp;
    frame.regs[4] = __riscv_return_tp;
    frame.regs[8] = __riscv_return_s[0];
    frame.regs[9] = __riscv_return_s[1];
    frame.regs[18] = __riscv_return_s[2];
    frame.regs[19] = __riscv_return_s[3];
    frame.regs[20] = __riscv_return_s[4];
    frame.regs[21] = __riscv_return_s[5];
    frame.regs[22] = __riscv_return_s[6];
    frame.regs[23] = __riscv_return_s[7];
    frame.regs[24] = __riscv_return_s[8];
    frame.regs[25] = __riscv_return_s[9];
    frame.regs[26] = __riscv_return_s[10];
    frame.regs[27] = __riscv_return_s[11];
    frame.regs[10] = code as usize;
}

#[no_mangle]
pub extern "C" fn riscv_trap_handler(frame: &mut TrapFrame) {
    if frame.scause == SCAUSE_USER_ECALL {
        frame.sepc = frame.sepc.wrapping_add(4);
        crate::handle_user_syscall(frame);
    } else {
        crate::handle_user_trap(frame);
    }
    // Single delivery seam for both syscall and trap returns; a no-op unless a
    // deliverable handler is pending and the frame still resumes user mode.
    crate::maybe_deliver_pending_signal(frame);
}

unsafe fn sbi_system_reset(reset_type: usize, reset_reason: usize) {
    let _error: usize;
    let _value: usize;

    core::arch::asm!(
        "ecall",
        inlateout("a0") reset_type => _error,
        inlateout("a1") reset_reason => _value,
        in("a6") SBI_FUNC_SYSTEM_RESET,
        in("a7") SBI_EXT_SYSTEM_RESET,
        options(nostack)
    );
}

unsafe fn sbi_set_timer(stime_value: u64) {
    let _error: usize;
    let _value: usize;

    core::arch::asm!(
        "ecall",
        inlateout("a0") stime_value as usize => _error,
        inlateout("a1") 0usize => _value,
        in("a6") SBI_FUNC_SET_TIMER,
        in("a7") SBI_EXT_TIME,
        options(nostack)
    );
}

unsafe fn read_sstatus() -> usize {
    let value: usize;
    core::arch::asm!("csrr {value}, sstatus", value = out(reg) value, options(nostack));
    value
}

unsafe fn read_sip() -> usize {
    let value: usize;
    core::arch::asm!("csrr {value}, sip", value = out(reg) value, options(nostack));
    value
}

unsafe fn read_time() -> u64 {
    let value: u64;
    core::arch::asm!("rdtime {value}", value = out(reg) value, options(nostack));
    value
}

/// Monotonic nanoseconds since boot from the rdtime counter. QEMU virt's
/// timebase is 10 MHz (100 ns per tick) — the same constant the budget-timer
/// tick math relies on, so it is validated by the production 100 ms cadence.
pub fn monotonic_nanos() -> u64 {
    unsafe { read_time() }.wrapping_mul(100)
}

unsafe fn write_stimecmp(value: u64) {
    core::arch::asm!("csrw 0x14d, {value}", value = in(reg) value, options(nostack));
}

unsafe fn set_sie_bits(bits: usize) {
    core::arch::asm!("csrs sie, {bits}", bits = in(reg) bits, options(nostack));
}

unsafe fn clear_sie_bits(bits: usize) {
    core::arch::asm!("csrc sie, {bits}", bits = in(reg) bits, options(nostack));
}

// ---- User-space MMU paging (Sv39) ----------------------------------------
//
// Per-run page table: kernel identity (RAM gigapage + MMIO megapage, U=0) plus
// a user window mapping canonical `[USER_BASE, USER_BASE+USER_SIZE)` linearly to
// the physical user buffer (U=1). Built while translation is OFF (bare mode),
// then installed via `satp` around user execution. See
// `.workbench/plans/2026-06-09-user-mmu-paging.md`.

use os_mod_kernel::paging::{
    BumpFrameAllocator, Frame, Sv39Table, GIGA_SIZE, MEGA_SIZE, PAGE_SIZE, PTE_A, PTE_D, PTE_G,
    PTE_R, PTE_U, PTE_W, PTE_X,
};

// Pre-set Accessed+Dirty on every leaf: this kernel does not implement the
// A/D page-fault fixup path, and RISC-V permits implementations to fault when
// A=0 (or D=0 on write), so software must set them up front.
const LEAF_AD: u64 = PTE_A | PTE_D;

/// QEMU `virt` RAM base (kernel, stack, .bss incl. the user buffer + frame pool).
const KERNEL_RAM_BASE: usize = 0x8000_0000;
/// MMIO cluster base: UART `0x10000000` + the eight virtio-mmio slots, covered
/// by one 2 MiB megapage `[0x10000000, 0x10200000)`. The test-finisher and PLIC
/// are only touched in bare mode (shutdown / not during user exec), so they need
/// no translated mapping.
const RV_MMIO_BASE: usize = 0x1000_0000;
/// Frame pool sized well above the worst case (~5 frames: root + low-GiB L1 +

/// Frame pool sized well above the worst case (~5 frames: root + low-GiB L1 +
/// two user L0 tables; kernel RAM and MMIO use huge-page leaves).
const RV_FRAME_POOL_FRAMES: usize = 64;

static mut RV_FRAME_POOL: [Frame; RV_FRAME_POOL_FRAMES] =
    [const { Frame::new() }; RV_FRAME_POOL_FRAMES];
static mut RV_FRAME_ALLOC: BumpFrameAllocator = BumpFrameAllocator::new();

/// Build a fresh per-run Sv39 table and return its `satp` value, or `None` if
/// the frame pool is exhausted (should never happen given the sizing above).
///
/// `buffer_pa` is the physical address of the user buffer; `user_base`/
/// `user_size` are the canonical user window (USER_BASE / USER_SIZE).
#[allow(dead_code)]
pub unsafe fn build_user_satp(
    buffer_pa: usize,
    user_base: usize,
    user_size: usize,
) -> Option<usize> {
    let pool = &mut *core::ptr::addr_of_mut!(RV_FRAME_POOL);
    let base = pool.as_ptr() as usize;
    let size = RV_FRAME_POOL_FRAMES * PAGE_SIZE;
    let alloc = &mut *core::ptr::addr_of_mut!(RV_FRAME_ALLOC);
    alloc.reset(base, size);

    let mut table = Sv39Table::new(alloc).ok()?;
    // Kernel RAM identity (1 GiB gigapage), supervisor R/W/X, global.
    table
        .map_range(
            KERNEL_RAM_BASE,
            KERNEL_RAM_BASE,
            GIGA_SIZE,
            PTE_R | PTE_W | PTE_X | PTE_G | LEAF_AD,
            alloc,
        )
        .ok()?;
    // MMIO identity (2 MiB megapage), supervisor R/W, global.
    table
        .map_range(
            RV_MMIO_BASE,
            RV_MMIO_BASE,
            MEGA_SIZE,
            PTE_R | PTE_W | PTE_G | LEAF_AD,
            alloc,
        )
        .ok()?;
    // User window: canonical USER_BASE -> physical user buffer, user R/W/X.
    table
        .map_range(
            user_base,
            buffer_pa,
            user_size,
            PTE_R | PTE_W | PTE_X | PTE_U | LEAF_AD,
            alloc,
        )
        .ok()?;
    Some(table.satp())
}

// ── D per-process VM (Stage 3): one DEDICATED page-table frame pool PER process
// window, so each live process's Sv39 table persists for its whole lifetime and is
// never clobbered by another process's table build or by build_user_satp's per-run
// RV_FRAME_POOL reset. RV_WINDOW_COUNT MUST match main.rs `WINDOW_COUNT` as the
// compile-time MAX: PT pools and metadata are sized by it, while main.rs
// ACTIVE_WINDOWS determines the runtime count backed by RAM. Sized like
// RV_FRAME_POOL (64): the 40 MiB user window is mapped with 4 KiB pages (it carries
// per-page protections, so megapages can't back it) → ~23 L0/L1 frames per table;
// 16 was too small (user map_range failed), 64 is the proven headroom.
#[cfg(feature = "stage1-per-process")]
// MUST match main.rs WINDOW_COUNT (6 on the genuine branch for iozone -t 4 + COW fork).
pub const RV_WINDOW_COUNT: usize = 6;
#[cfg(feature = "stage1-per-process")]
const RV_WINDOW_PT_POOL_FRAMES: usize = 64;
#[cfg(feature = "stage1-per-process")]
static mut RV_WINDOW_PT_POOLS: [[Frame; RV_WINDOW_PT_POOL_FRAMES]; RV_WINDOW_COUNT] =
    [const { [const { Frame::new() }; RV_WINDOW_PT_POOL_FRAMES] }; RV_WINDOW_COUNT];
#[cfg(feature = "stage1-per-process")]
static mut RV_WINDOW_PT_ALLOC: [BumpFrameAllocator; RV_WINDOW_COUNT] =
    [const { BumpFrameAllocator::new() }; RV_WINDOW_COUNT];

/// D per-process VM: build the Sv39 table for process window `window_idx` over its
/// physical buffer `buffer_pa`, returning the satp. Each window has its own PT pool
/// (rebuilt in place when the window is reused for a new process), so concurrent
/// processes never share page-table frames. Mappings mirror build_user_satp.
#[cfg(feature = "stage1-per-process")]
#[allow(dead_code)]
pub unsafe fn build_window_satp(
    window_idx: usize,
    buffer_pa: usize,
    user_base: usize,
    user_size: usize,
) -> Option<usize> {
    if window_idx >= RV_WINDOW_COUNT {
        return None;
    }
    let pool = &mut (*core::ptr::addr_of_mut!(RV_WINDOW_PT_POOLS))[window_idx];
    let base = pool.as_ptr() as usize;
    let size = RV_WINDOW_PT_POOL_FRAMES * PAGE_SIZE;
    let alloc = &mut (*core::ptr::addr_of_mut!(RV_WINDOW_PT_ALLOC))[window_idx];
    alloc.reset(base, size);
    let mut table = Sv39Table::new(alloc).ok()?;
    table
        .map_range(
            KERNEL_RAM_BASE,
            KERNEL_RAM_BASE,
            GIGA_SIZE,
            PTE_R | PTE_W | PTE_X | PTE_G | LEAF_AD,
            alloc,
        )
        .ok()?;
    table
        .map_range(
            RV_MMIO_BASE,
            RV_MMIO_BASE,
            MEGA_SIZE,
            PTE_R | PTE_W | PTE_G | LEAF_AD,
            alloc,
        )
        .ok()?;
    table
        .map_range(
            user_base,
            buffer_pa,
            user_size,
            PTE_R | PTE_W | PTE_X | PTE_U | LEAF_AD,
            alloc,
        )
        .ok()?;
    Some(table.satp())
}

// ── Step B (lazy demand paging) — feature `stage1-lazy-demand`, RV-only ──
// All dead-code until the trap handler + builders are wired (B2/B3); the eager
// path above is untouched. The fixed 40 MiB window stays the backing; only leaf
// PTE population becomes lazy.

/// Build the per-window Sv39 table with kernel gigapage + MMIO megapage mapped
/// EAGERLY (as `build_window_satp`), but the user window's intermediate skeleton
/// (root + L1 + all L0 tables) RESERVED with no valid leaves. User leaves are
/// filled one-at-a-time by the demand-fault handler via `map_user_page`. Because
/// every L0 table is pre-built here, a demand fill allocates ZERO frames, so
/// `OutOfFrames` is unreachable for the user range (the red-team's ENOMEM-kill
/// fix). `_buffer_pa` is unused (lazy maps no user leaf up front) but kept so
/// call sites swap cleanly with `build_window_satp`.
#[cfg(feature = "stage1-lazy-demand")]
#[allow(dead_code)]
pub unsafe fn build_window_satp_lazy(
    window_idx: usize,
    _buffer_pa: usize,
    user_base: usize,
    user_size: usize,
) -> Option<usize> {
    if window_idx >= RV_WINDOW_COUNT {
        return None;
    }
    let pool = &mut (*core::ptr::addr_of_mut!(RV_WINDOW_PT_POOLS))[window_idx];
    let base = pool.as_ptr() as usize;
    let size = RV_WINDOW_PT_POOL_FRAMES * PAGE_SIZE;
    let alloc = &mut (*core::ptr::addr_of_mut!(RV_WINDOW_PT_ALLOC))[window_idx];
    alloc.reset(base, size);
    let mut table = Sv39Table::new(alloc).ok()?;
    table
        .map_range(
            KERNEL_RAM_BASE,
            KERNEL_RAM_BASE,
            GIGA_SIZE,
            PTE_R | PTE_W | PTE_X | PTE_G | LEAF_AD,
            alloc,
        )
        .ok()?;
    table
        .map_range(
            RV_MMIO_BASE,
            RV_MMIO_BASE,
            MEGA_SIZE,
            PTE_R | PTE_W | PTE_G | LEAF_AD,
            alloc,
        )
        .ok()?;
    // User window: reserve the intermediate skeleton only — NO leaves (lazy).
    table.reserve_tables(user_base, user_size, alloc).ok()?;
    Some(table.satp())
}

