// ---- LoongArch software-TLB refill (linear user window) ------------------
//
// LoongArch maps a PAIR of pages per TLB entry (even page at bit12=0, odd at
// bit12=1; VPPN excludes bit 12). With STLBPS=12 (4 KiB) a TLB entry covers an
// 8 KiB pair. Because our user window is a LINEAR map (USER_BASE -> buffer_pa,
// contiguous), the refill handler needs no page-table walk: PA = buffer_pa +
// (VA - user_base). Kernel + MMIO are reached via DMW (not the TLB).
//
// TLBELO (TLBRELO0/1) bit layout (Linux arch/loongarch/include/asm/loongarch.h):
//   V bit0, WE(dirty/writable) bit1, PLV bits3:2, CCA(cache) bits5:4,
//   GLOBAL bit6, PFN = PA[47:12] (so TLBELO = (PA & ~0xfff) | flags),
//   NR bit61, NX bit62, RPLV bit63. CCA: 0=SUC(uncached), 1=CC(cached).
pub const LA_TLBELO_V: usize = 1 << 0;
pub const LA_TLBELO_WE: usize = 1 << 1;
pub const LA_TLBELO_PLV_SHIFT: usize = 2;
pub const LA_TLBELO_CCA_SHIFT: usize = 4;
pub const LA_TLBELO_G: usize = 1 << 6;
pub const LA_TLBELO_NX: usize = 1 << 62;
pub const LA_PLV_USER: usize = 3;
pub const LA_PLV_KERNEL: usize = 0;
pub const LA_CCA_CACHED: usize = 1;
/// SUC — strongly-ordered uncached. v1 maps everything (kernel/MMIO/user)
/// uncached: the LA kernel already runs uncached today (reset CRMD.DATF=DATM=0),
/// so this is coherence-free and zero perf-regression vs the pre-paging build.
pub const LA_CCA_UNCACHED: usize = 0;
/// Page-size shift (4 KiB) carried in CSR.TLBREHI.PS (bits [5:0]) AND STLBPS.PS.
/// On a refill, hardware (and QEMU) take the filled entry's page size from
/// TLBREHI.PS — leaving it 0 installs a 1-byte page and re-faults forever.
pub const LA_PS_4K: usize = 12;
/// 8 KiB even/odd pair mask (low 13 bits) for STLBPS=12.
const LA_PAIR_MASK: usize = (PAGE_SIZE * 2) - 1;
const LA_TLBELO_PFN_MASK: usize = !(PAGE_SIZE - 1) & ((1usize << 48) - 1);

/// v1 TLBELO flags for a user-window page: V, writable, PLV3, uncached, global.
pub const LA_USER_FLAGS: usize = LA_TLBELO_V
    | LA_TLBELO_WE
    | (LA_PLV_USER << LA_TLBELO_PLV_SHIFT)
    | (LA_CCA_UNCACHED << LA_TLBELO_CCA_SHIFT)
    | LA_TLBELO_G;
/// v1 TLBELO flags for a kernel/MMIO identity page: V, writable, PLV0, uncached,
/// global. Mapped at PLV0 so a stray PLV3 user access to it takes a privilege
/// fault (→ the general trap kills the process) rather than aliasing kernel RAM.
pub const LA_KERNEL_FLAGS: usize = LA_TLBELO_V
    | LA_TLBELO_WE
    | (LA_PLV_KERNEL << LA_TLBELO_PLV_SHIFT)
    | (LA_CCA_UNCACHED << LA_TLBELO_CCA_SHIFT)
    | LA_TLBELO_G;

/// Compute the TLB-refill values `(tlbrehi, tlbelo0, tlbelo1)` for a faulting
/// virtual address `badv` (v1 paging model). A page inside the linear user
/// window `[user_base, user_base+user_size)` maps to `buffer_pa + (VA -
/// user_base)` at PLV3; every other page maps identity (PA = VA) at PLV0. All
/// pages are R/W/X, global, uncached. This is the exact pure logic the asm
/// refill handler in `boot/loongarch64.S` mirrors, so it is the verified spec.
pub fn la_linear_refill(
    badv: usize,
    buffer_pa: usize,
    user_base: usize,
    user_size: usize,
) -> (usize, usize, usize) {
    let pair_base = badv & !LA_PAIR_MASK; // even page of the 8 KiB pair
    let entry = |va: usize| -> usize {
        let (pa, flags) = if va >= user_base && va < user_base.wrapping_add(user_size) {
            (buffer_pa.wrapping_add(va - user_base), LA_USER_FLAGS)
        } else {
            (va, LA_KERNEL_FLAGS) // identity, PLV0 (kernel + MMIO)
        };
        (pa & LA_TLBELO_PFN_MASK) | flags
    };
    // TLBREHI carries the VPPN (bits [.:13]) AND the page-size shift in PS
    // (bits [5:0]); pair_base has its low 13 bits clear, so OR-ing the shift
    // sets PS without disturbing VPPN.
    (
        pair_base | LA_PS_4K,
        entry(pair_base),
        entry(pair_base + PAGE_SIZE),
    )
}

// ---- LoongArch software-TLB refill (PAGE-TABLE walk, the per-process AddrSpace) --------
//
// The per-process LA AddrSpace uses LaPt (src/vm.rs), whose IN-MEMORY PTE format is the
// software layout below; the asm refill handler walks the 3-level table and converts each
// leaf to TLBELO via `la_pt_pte_to_tlbelo`. These bit positions MUST match vm.rs::LaPt's
// LA_PTE_* constants (the single source of truth lives here; vm.rs mirrors them). Distinct
// from the linear `la_linear_refill` path, which stays the default until a PGD root is set.
pub const LA_PT_V: u64 = 1 << 0; // valid
pub const LA_PT_LEAF: u64 = 1 << 1; // 1 = 4 KiB leaf page; 0 = pointer to the next table
pub const LA_PT_R: u64 = 1 << 2; // readable
pub const LA_PT_W: u64 = 1 << 3; // writable (fork_cow down-protect clears this in place)
pub const LA_PT_X: u64 = 1 << 4; // executable
pub const LA_PT_U: u64 = 1 << 5; // user-accessible (PLV3)

/// Convert a LaPt in-memory LEAF PTE to a TLBELO value — the exact bit math the asm refill
/// handler mirrors (so it is the host-verified spec). An invalid PTE (V=0, page not mapped)
/// → 0, i.e. TLBELO.V=0, so the access raises a page-invalid trap → the demand-paging path.
/// A valid leaf → `PFN | V | G | (W?WE:0) | PLV(U?3:0) | uncached(CCA=0) | (X?0:NX)`. A
/// writable user page (R|W|U) yields exactly `LA_USER_FLAGS` (0x4F) in the low bits, with NX
/// set (data, not executable); a code page (R|X|U) yields 0x4D + NX clear; an RO user page
/// (R|U — e.g. after a COW down-protect) yields 0x4D, so a store page-faults = the COW-break
/// trigger. Mirrors `la_linear_refill`'s `(pa & PFN_MASK) | flags`, but flags come from the
/// per-page PTE rather than a fixed window flag.
pub fn la_pt_pte_to_tlbelo(pte: u64) -> usize {
    if pte & LA_PT_V == 0 {
        return 0; // not present → TLBELO.V=0 → page-invalid trap → demand paging
    }
    let mut elo = ((pte as usize) & LA_TLBELO_PFN_MASK) | LA_TLBELO_V | LA_TLBELO_G;
    if pte & LA_PT_W != 0 {
        elo |= LA_TLBELO_WE;
    }
    let plv = if pte & LA_PT_U != 0 {
        LA_PLV_USER
    } else {
        LA_PLV_KERNEL
    };
    elo |= plv << LA_TLBELO_PLV_SHIFT;
    // CCA uncached (0) — matches the linear path; no bits to set.
    if pte & LA_PT_X == 0 {
        elo |= LA_TLBELO_NX; // W^X: a non-executable page gets NX
    }
    elo
}

