    /// creator's. A no-op on frames that have no separate tp (e.g. TestFrame is
    /// backed by a field; the snapshot path never calls this).
    fn set_thread_pointer(&mut self, tp: usize);
    fn rewind_syscall(&mut self);
}

impl ProcessFrame for TestFrame {
    fn set_return_value(&mut self, value: isize) {
        self.result = value;
    }

