use crate::paging::{MapError, PAGE_SIZE};

// ---------------------------------------------------------------------------
// Prot — abstract page permissions (R/W/X/U), arch-independent.
// ---------------------------------------------------------------------------

#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub struct Prot(pub u8);

impl Prot {
    pub const R: Prot = Prot(1);
    pub const W: Prot = Prot(2);
    pub const X: Prot = Prot(4);
    pub const U: Prot = Prot(8);

    pub const fn empty() -> Prot {
        Prot(0)
    }
    pub const fn union(self, o: Prot) -> Prot {
        Prot(self.0 | o.0)
    }
    pub const fn contains(self, o: Prot) -> bool {
        self.0 & o.0 == o.0
    }
    pub const fn readable(self) -> bool {
        self.contains(Prot::R)
    }
    pub const fn writable(self) -> bool {
        self.contains(Prot::W)
    }
    pub const fn executable(self) -> bool {
        self.contains(Prot::X)
    }
}

// ---------------------------------------------------------------------------
// Per-frame refcount — pure functions (host-tested), keyed by frame index.
// The substrate for BOTH COW (incref on fork-share, copy-on-write-fault) and
// the page cache (shared file-page frames). Mirrors paging.rs bump_fill style.
// ---------------------------------------------------------------------------

#[inline]
pub fn frame_index(pool_base: usize, pa: usize) -> usize {
    (pa - pool_base) / PAGE_SIZE
}

/// A freshly-allocated frame: set its refcount to 1.
pub fn ref_set_one(refcount: &mut [u16], idx: usize) {
    refcount[idx] = 1;
}

/// Share one more reference (COW fork / page-cache share).
pub fn ref_inc(refcount: &mut [u16], idx: usize) {
    refcount[idx] = refcount[idx].saturating_add(1);
}

/// Drop one reference; returns true when it hits 0 (the caller should then free
/// the frame back to the `FrameFreeList`).
pub fn ref_dec(refcount: &mut [u16], idx: usize) -> bool {
    if refcount[idx] > 0 {
        refcount[idx] -= 1;
    }
    refcount[idx] == 0
}

// ---------------------------------------------------------------------------
// FrameAllocator — FrameFreeList + a parallel refcount table.
// The refcount backing is supplied externally (kernel = a static array; tests =
// a heap slice) so the same type serves both no_std kernel and host tests.
// ---------------------------------------------------------------------------

pub struct FrameAllocator {
    free: crate::paging::FrameFreeList,
    pool_base: usize,
    refcount: *mut u16,
    refcount_len: usize,
}

// SAFETY: single-hart kernel; all access is serialized through the one owner.
// Mirrors how the snapshot model already shares static-mut frame structures.
unsafe impl Send for FrameAllocator {}
unsafe impl Sync for FrameAllocator {}

impl FrameAllocator {
    pub const fn new() -> Self {
        Self {
            free: crate::paging::FrameFreeList::new(),
            pool_base: 0,
            refcount: core::ptr::null_mut(),
            refcount_len: 0,
        }
    }

    /// Chain every frame in `[base, base+size)` onto the free list and record the
    /// refcount backing (which must hold at least `size / PAGE_SIZE` entries).
    ///
    /// # Safety
    /// `[base, base+size)` must be real, writable, frame-aligned memory owned by
    /// no one else (bare-mode kernel RAM, or a host buffer in tests); `refcount`
    /// must point at `refcount_len >= size/PAGE_SIZE` valid `u16`s.
    pub unsafe fn init(
        &mut self,
        base: usize,
        size: usize,
        refcount: *mut u16,
        refcount_len: usize,
    ) {
        self.free.init(base, size);
        self.pool_base = base;
        self.refcount = refcount;
        self.refcount_len = refcount_len;
        // Start every frame at refcount 0 (free).
        core::ptr::write_bytes(refcount, 0, refcount_len);
    }

    #[inline]
    fn slice(&self) -> &mut [u16] {
        // SAFETY: set in `init` to a valid `refcount_len`-long region; single-hart.
        unsafe { core::slice::from_raw_parts_mut(self.refcount, self.refcount_len) }
    }

    /// Allocate one zeroed frame (refcount := 1), returning its PA.
    ///
    /// # Safety
    /// The pool must have been `init`-ed over valid memory.
    pub unsafe fn alloc(&mut self) -> Option<usize> {
        let pa = self.free.alloc_zeroed()?;
        let idx = frame_index(self.pool_base, pa);
        ref_set_one(self.slice(), idx);
        Some(pa)
    }

    /// True if `pa` is a frame inside this allocator's pool (refcount-tracked).
    /// SysV-SHM frames (Backend::Shared) live in a STATIC kernel region OUTSIDE
    /// the pool: they are never alloc'd/incref'd/freed. incref/decref/refcount_of
    /// must no-op on them — a fork child maps the static shm frame, and at the
    /// child's teardown `free_all_frames` would otherwise decref that non-pool PA,
    /// which both underflows `frame_index` (OOB panic) AND, if it didn't panic,
    /// would push a static address onto the free list (corruption). The guard
    /// keeps the "shm frames are not refcounted" invariant honest at every entry.
    #[inline]
    pub fn in_pool(&self, pa: usize) -> bool {
        pa >= self.pool_base && (pa - self.pool_base) / PAGE_SIZE < self.refcount_len
    }

    /// Share one more reference to `pa` (COW fork / page-cache share).
    ///
    /// # Safety
    /// `pa` must be a live frame previously returned by `alloc`.
    pub unsafe fn incref(&mut self, pa: usize) {
        if !self.in_pool(pa) {
            return; // static shm frame — not refcounted
        }
        let idx = frame_index(self.pool_base, pa);
        ref_inc(self.slice(), idx);
    }

    /// Drop one reference to `pa`; frees it back to the pool when the count hits
    /// 0. Returns whether the frame was freed.
    ///
    /// # Safety
    /// `pa` must be a live frame previously returned by `alloc`.
    pub unsafe fn decref(&mut self, pa: usize) -> bool {
        if !self.in_pool(pa) {
            return false; // static shm frame — never refcounted, never freed
        }
        let idx = frame_index(self.pool_base, pa);
        let freed = ref_dec(self.slice(), idx);
        if freed {
            self.free.free(pa);
        }
        freed
    }

    pub fn refcount_of(&self, pa: usize) -> u16 {
        if !self.in_pool(pa) {
            return 1; // static shm frame — treat as unshared (never COW-broken)
        }
        let idx = frame_index(self.pool_base, pa);
        self.slice()[idx]
    }

    pub fn free_count(&self) -> usize {
        self.free.free_count()
    }
}

