pub enum Backend {
    /// Anonymous memory: a page faults in as a fresh zeroed frame.
    Anonymous,
    /// File-backed: a page faults in from the page cache at `offset..offset+len`,
    /// zero-filling past `len` (the .so / mmap primitive, Phase 3).
    FileBacked {
        node: usize,
        offset: usize,
        len: usize,
    },
    /// Shared: maps user pages directly onto a fixed physical region (SysV SHM).
    /// `phys_base` is the page-aligned PA backing `area.start`; page `va` maps to
    /// `phys_base + (va - area.start)`. The SAME frames are shared by every process
    /// that attaches AND across fork (see `fork_cow`), so writes are mutually
    /// visible — real cross-process shared memory on the per-process VM. NOT COW:
    /// sharing is the contract, so a write must NOT break it into a private copy.
    Shared { phys_base: usize },
    /// SharedFile: a MAP_SHARED file mapping (from origin/main 98c9964 — the LTP
    /// results-IPC file). Unlike `Shared`, the frames are allocated + filled + eager-
    /// mapped + refcounted (no fixed phys region, never demand-faulted). Shared across
    /// fork (incref, not copied) and never COW-broken — same sharing contract as
    /// `Shared`, just a different backing mechanism.
    SharedFile,
}

#[derive(Clone, Copy, Debug)]
pub struct MapArea {
    pub start: usize,
    pub end: usize,
    pub prot: Prot,
    pub backend: Backend,
}

impl MapArea {
    pub fn new(start: usize, end: usize, prot: Prot, backend: Backend) -> Self {
        Self {
            start,
            end,
            prot,
            backend,
        }
    }
    pub fn contains(&self, va: usize) -> bool {
        va >= self.start && va < self.end
    }
}

/// Find the area covering `va` (linear scan; the area count is small).
pub fn find_area(areas: &[MapArea], va: usize) -> Option<&MapArea> {
    areas.iter().find(|a| a.contains(va))
}

pub const MAX_AREAS: usize = 64;

