pub extern "C" fn kernel_main(_arg0: usize, _arg1: usize, _arg2: usize) -> ! {
    crate::println!("OS_mod kernel start arch={}", arch::ARCH);
    crate::println!("OS_mod BUILD {}", BUILD_TAG);
    #[cfg(feature = "arch-riscv64")]
    report_dtb_memory(_arg1);
    #[cfg(all(feature = "stage1-per-process", feature = "arch-riscv64"))]
    unsafe {
        if init_window_region().is_err() {
            shutdown::failure();
        }
    }
    // Real time: every time syscall now reports the arch monotonic counter
    // instead of the legacy fabricated tick model (which remains only as the
    // host-test fallback).
    os_mod_kernel::syscall::install_real_time_source(arch::monotonic_nanos);
    // Wall bound for the last unbounded kernel surface: per-file-read budget
    // (script/ELF reads — the cycle57 slow-crawl wedge window).
    os_mod_kernel::fs::ext4::install_read_wall_clock(arch::monotonic_nanos);
    // One-time MMU paging init (LoongArch opens DMW0 + sets STLBPS/TLBRENTRY;
    // RISC-V is a no-op). Translation is still off until a user run enables it.
    arch::init_paging();
    // Real-VM boot self-test: prove the AddrSpace machinery runs on real hardware
    // before the exec path is wired (OFF unless the addrspace feature is built).
    #[cfg(all(feature = "addrspace", feature = "arch-riscv64"))]
    unsafe {
        addrspace_self_test();
    }
    #[cfg(all(feature = "la-addrspace-probe", feature = "arch-loongarch64"))]
    unsafe {
        // The ⑤⑥ self-test (la_addrspace_run_embedded) is SUPERSEDED by the ⑦⑧⑩
        // real-run path: addrspace_try_run_la (wired into run_user_elf_with_args) runs
        // a REAL static LA ELF on the LaPt AddrSpace end-to-end (enter + demand-fault +
        // syscall dispatch + write + clean exit), a strictly stronger gate. The
        // self-test is not invoked here because it leaves boot state that wedges the
        // post-boot disk discovery (a pre-existing probe-build interaction); kept
        // (referenced) for reference. Verify: .workbench/repro/verify-la-real.sh.
        let _ = la_addrspace_run_embedded;
    }
    #[cfg(any(feature = "arch-riscv64", feature = "arch-loongarch64"))]
    {
        let alive = probe_budget_timer();
        unsafe {
            *core::ptr::addr_of_mut!(BUDGET_TIMER_ALIVE) = alive;
        }
        crate::println!(
            "OS_mod budget timer probe: {}",
            if alive { "alive" } else { "dead" }
        );
    }
    match run_discovered_tests() {
        Ok(count) => {
            crate::println!("OS_mod discovered script count={}", count);
            crate::println!("OS_mod all discovered scripts handled");
        }
        Err(error) => {
            crate::println!("OS_mod test disk runner unavailable: {}", error.label());
        }
    }
    shutdown::success()
}

#[cfg(feature = "arch-riscv64")]
fn run_discovered_tests() -> Result<usize, RunError> {
    crate::println!("OS_mod probing block device");
    let mut device = unsafe { os_mod_kernel::virtio::mmio::probe_riscv()? };
    crate::println!("OS_mod block device ready");
    run_on_block_device(&mut device)
}

#[cfg(feature = "arch-loongarch64")]
fn run_discovered_tests() -> Result<usize, RunError> {
    crate::println!("OS_mod probing block device");
    let mut device = unsafe { os_mod_kernel::virtio::pci::VirtioPciBlock::probe_loongarch()? };
    crate::println!("OS_mod block device ready");
