fn run_on_block_device<D: BlockDevice>(device: &mut D) -> Result<usize, RunError> {
    crate::println!("OS_mod opening ext4");
    let mut reader = Ext4Reader::open(device)?;
    crate::println!("OS_mod ext4 ready");
    let mut scripts = DiscoveredScripts::<MAX_DISCOVERED_SCRIPTS>::new();
    crate::println!("OS_mod discovering scripts");
    reader.discover_scripts(&mut scripts)?;
    crate::println!("OS_mod script discovery ready");

    let mut script_buf = [0u8; MAX_SCRIPT_BYTES];
    let mut sink = ConsoleSink;

    for script in scripts.as_slice() {
        let path = match script.path.as_str() {
            Ok(path) => path,
