    pub fn parse(bytes: &'a [u8]) -> Result<Self, ElfError> {
        if bytes.len() < ELF_HEADER_SIZE {
            return Err(ElfError::HeaderTooSmall);
        }
        if bytes.get(0..4) != Some(b"\x7fELF") {
            return Err(ElfError::BadMagic);
        }
        if bytes[EI_CLASS] != ELFCLASS64 {
            return Err(ElfError::UnsupportedClass);
        }
        if bytes[EI_DATA] != ELFDATA2LSB {
            return Err(ElfError::UnsupportedEndian);
        }
        if bytes[EI_VERSION] != EV_CURRENT {
            return Err(ElfError::UnsupportedVersion);
        }

        let file_type = match read_u16(bytes, 16)? {
            ET_EXEC => ElfType::Executable,
            ET_DYN => ElfType::PositionIndependent,
            _ => return Err(ElfError::UnsupportedType),
        };

        let machine = match read_u16(bytes, 18)? {
            EM_RISCV => ElfMachine::Riscv64,
            EM_LOONGARCH => ElfMachine::LoongArch64,
            _ => return Err(ElfError::UnsupportedMachine),
        };
        if read_u32(bytes, 20)? != EV_CURRENT as u32 {
            return Err(ElfError::UnsupportedVersion);
        }

        let entry = read_u64(bytes, 24)?;
        let program_header_offset = read_u64(bytes, 32)?;
        let header_size = read_u16(bytes, 52)? as usize;
        let program_header_entry_size = read_u16(bytes, 54)?;
        let program_header_count = read_u16(bytes, 56)?;
        let section_header_offset = read_u64(bytes, 40)?;
        let section_header_entry_size = read_u16(bytes, 58)?;
        let section_header_count = read_u16(bytes, 60)?;
        let section_name_index = read_u16(bytes, 62)?;

        if header_size < ELF_HEADER_SIZE {
            return Err(ElfError::HeaderTooSmall);
        }
        if program_header_entry_size != 0 && program_header_entry_size as usize != 56 {
            return Err(ElfError::UnsupportedProgramHeaderSize);
        }
        program_header_range(
            bytes.len(),
            program_header_offset,
            program_header_entry_size,
            program_header_count,
        )?;
        if section_header_count != 0 && section_header_entry_size as usize != 64 {
            return Err(ElfError::UnsupportedSectionHeaderSize);
        }
        section_header_range(
            bytes.len(),
            section_header_offset,
            section_header_entry_size,
            section_header_count,
        )?;

        Ok(Self {
            file_type,
            machine,
            entry,
            program_header_offset,
            program_header_entry_size,
            program_header_count,
            section_header_offset,
            section_header_entry_size,
            section_header_count,
            section_name_index,
            bytes,
        })
    }

