/// Wall clock for the per-file read budget; installed once by `kernel_main`
/// (None on the host, where reads are memory-backed and instant).
static mut READ_WALL_CLOCK: Option<fn() -> u64> = None;
/// Generous allowance per file read: a healthy 6 MiB ELF reads in well under
/// 2 s; a read still running after this long is the slow-crawl class.
const READ_WALL_BUDGET_NANOS: u64 = 20_000_000_000;
/// Check cadence: every N chunks, so the healthy path pays ~zero overhead.
const READ_WALL_CHECK_CHUNKS: usize = 64;

pub fn install_read_wall_clock(clock: fn() -> u64) {
    unsafe {
        READ_WALL_CLOCK = Some(clock);
    }
}

fn read_wall_deadline() -> Option<(fn() -> u64, u64)> {
    let clock = unsafe { *core::ptr::addr_of!(READ_WALL_CLOCK) }?;
    Some((clock, clock().saturating_add(READ_WALL_BUDGET_NANOS)))
}

