}

impl<const N: usize> ByteBuf<N> {
    pub const fn new() -> Self {
        Self {
            bytes: [0; N],
            len: 0,
        }
    }

    pub fn from_slice(value: &[u8]) -> Result<Self, Ext4Error> {
        let mut out = Self::new();
        out.push_slice(value)?;
        Ok(out)
    }

    pub fn clear(&mut self) {
        self.len = 0;
    }

    pub fn push_byte(&mut self, value: u8) -> Result<(), Ext4Error> {
        if self.len == N {
            return Err(Ext4Error::PathTooLong);
        }
        self.bytes[self.len] = value;
        self.len += 1;
        Ok(())
    }

    pub fn push_slice(&mut self, value: &[u8]) -> Result<(), Ext4Error> {
        if self.len + value.len() > N {
            return Err(Ext4Error::PathTooLong);
        }
        let end = self.len + value.len();
        self.bytes[self.len..end].copy_from_slice(value);
        self.len = end;
        Ok(())
    }

    pub fn len(&self) -> usize {
        self.len
    }

    pub fn is_empty(&self) -> bool {
        self.len == 0
    }

    pub fn as_slice(&self) -> &[u8] {
        &self.bytes[..self.len]
    }

    pub fn as_str(&self) -> Result<&str, core::str::Utf8Error> {
        core::str::from_utf8(self.as_slice())
    }
}

