pub(crate) fn sys_dup(ctx: &mut SyscallContext, old_fd: usize) -> isize {
    if old_fd >= FD_LIMIT || ctx.fds[old_fd] == FileDescriptor::Closed {
        return -EBADF;
    }
    ctx.alloc_fd(ctx.fds[old_fd])
}

pub(crate) fn sys_dup3(
    ctx: &mut SyscallContext,
    old_fd: usize,
    new_fd: usize,
    flags: usize,
) -> isize {
    if flags & !O_CLOEXEC != 0 {
        return -EINVAL;
    }
    if old_fd >= FD_LIMIT || new_fd >= FD_LIMIT || ctx.fds[old_fd] == FileDescriptor::Closed {
        return -EBADF;
    }
    if old_fd == new_fd {
        return old_fd as isize;
    }
    ctx.fds[new_fd] = ctx.fds[old_fd];
    new_fd as isize
}

pub(crate) fn sys_fcntl(ctx: &mut SyscallContext, fd: usize, cmd: usize, arg: usize) -> isize {
    if fd >= FD_LIMIT || ctx.fds[fd] == FileDescriptor::Closed {
        return -EBADF;
    }
    match cmd {
        F_DUPFD | F_DUPFD_CLOEXEC => {
            if arg >= FD_LIMIT {
                return -EINVAL;
            }
            for index in arg..FD_LIMIT {
                if ctx.fds[index] == FileDescriptor::Closed {
                    ctx.fds[index] = ctx.fds[fd];
                    return index as isize;
                }
            }
            -EBADF
        }
        F_GETFD => 0,
        F_SETFD => 0,
        F_GETFL => match ctx.fds[fd] {
            FileDescriptor::Directory { .. } => O_DIRECTORY as isize,
            FileDescriptor::File { append, .. } if append => O_APPEND as isize,
            _ => 0,
        },
        F_SETFL => 0,
        _ => -EINVAL,
    }
}

pub(crate) fn sys_ioctl(ctx: &SyscallContext, fd: usize, _request: usize, _arg: usize) -> isize {
    if fd >= FD_LIMIT || ctx.fds[fd] == FileDescriptor::Closed {
        return -EBADF;
    }
    0
}

pub(crate) fn sys_close(ctx: &mut SyscallContext, fd: usize) -> isize {
    if fd >= FD_LIMIT || ctx.fds[fd] == FileDescriptor::Closed {
        return -EBADF;
    }
    let removed_node = match ctx.fds[fd] {
        FileDescriptor::File { node, .. } | FileDescriptor::Directory { node, .. }
            if ctx.nodes[node].removed =>
        {
            Some(node)
        }
        _ => None,
    };
    ctx.fds[fd] = FileDescriptor::Closed;
    if let Some(node) = removed_node {
        ctx.cleanup_removed_node_if_unreferenced(node);
    }
    0
}

