        // Non-null aligned dangling ptr, len 0 — never dereferenced before the
        // first `rebind` (a process is always bound in before any access).
        Backing {
            ptr: core::ptr::NonNull::<u8>::dangling().as_ptr(),
            len: 0,
        }
    }

    /// Point this view at a process's contiguous frame window [ptr, ptr+len).
    fn rebind(&mut self, ptr: *mut u8, len: usize) {
        self.ptr = ptr;
        self.len = len;
    }
}

#[cfg(feature = "stage1-per-process")]
impl core::ops::Deref for Backing {
    type Target = [u8];
    #[inline(always)]
    fn deref(&self) -> &[u8] {
        // SAFETY: rebound to a live, owned-by-current-process frame window before
        // any user-memory access; len 0 + dangling before the first rebind.
        unsafe { core::slice::from_raw_parts(self.ptr, self.len) }
    }
}

#[cfg(feature = "stage1-per-process")]
impl core::ops::DerefMut for Backing {
    #[inline(always)]
    fn deref_mut(&mut self) -> &mut [u8] {
        // SAFETY: see `deref`.
        unsafe { core::slice::from_raw_parts_mut(self.ptr, self.len) }
