fn run_basic_script<D: BlockDevice>(
    reader: &mut Ext4Reader<'_, D>,
    info: &runner::ScriptInfo<'_>,
    text: &str,
    sink: &mut ConsoleSink,
) -> Result<(), RunError> {
    unsafe {
        (*core::ptr::addr_of_mut!(SCRIPT_TEXT_STORAGE)).reset();
    }
    let mut plan = BasicRunPlan::new();
    collect_basic_plan(reader, info.path, text, &mut plan)?;
    if plan.is_empty() {
        return Err(RunError::UnsupportedScript);
    }

    runner::render_basic_start(info, sink);
    for item in plan.items() {
        let Ok(test) = item.test.as_str() else {
            runner::render_basic_unsupported_subtest("<non-utf8>", sink);
            continue;
        };
        runner::render_basic_test_start(test, sink);
        match run_basic_elf(reader, item.elf.as_slice()) {
            Ok(code) => {
                crate::println!("OS_mod basic {} exit={}", test, code);
            }
            Err(error) => {
                crate::println!("OS_mod basic {} unavailable: {}", test, error.label());
            }
        }
    }
    runner::render_basic_end(info, sink);
    Ok(())
}

