        self.read_at(descriptor_offset, &mut descriptor[..read_len])?;

        let inode_table_lo = read_u32(&descriptor, 8)? as u64;
        let inode_table_hi = if self.superblock.descriptor_size >= 64 {
            read_u32(&descriptor, 40).unwrap_or(0) as u64
        } else {
            0
        };
        let inode_table_block = inode_table_lo | (inode_table_hi << 32);
        if inode_table_block == 0 {
            return Err(Ext4Error::InvalidGroupDescriptor);
        }
        Ok(GroupDescriptor { inode_table_block })
    }

    fn collect_extents_for_blocks(
        &mut self,
        inode: &Inode,
        blocks_needed: u32,
        extents: &mut FixedList<Extent, MAX_EXTENTS>,
    ) -> Result<(), Ext4Error> {
        if blocks_needed == 0 {
            return Ok(());
        }

        let header = parse_extent_header(&inode.block)?;
        match header.depth {
            0 => parse_extent_entries(
                &inode.block,
                EXTENT_HEADER_BYTES,
                header.entries,
                blocks_needed,
                extents,
            ),
            1 => {
                let mut leaf = [0u8; MAX_BLOCK_SIZE];
                for index in 0..header.entries as usize {
                    let offset = EXTENT_HEADER_BYTES + index * EXTENT_ENTRY_BYTES;
                    if offset + EXTENT_ENTRY_BYTES > inode.block.len() {
                        return Err(Ext4Error::InvalidExtent);
                    }
                    let logical = read_u32(&inode.block, offset)?;
                    if logical >= blocks_needed {
                        continue;
                    }
                    let leaf_lo = read_u32(&inode.block, offset + 4)? as u64;
                    let leaf_hi = read_u16(&inode.block, offset + 8)? as u64;
                    let leaf_block = leaf_lo | (leaf_hi << 32);
                    self.read_block(leaf_block, &mut leaf[..self.superblock.block_size])?;
                    let leaf_header = parse_extent_header(&leaf)?;
                    if leaf_header.depth != 0 {
                        return Err(Ext4Error::UnsupportedExtent);
                    }
                    parse_extent_entries(
                        &leaf,
                        EXTENT_HEADER_BYTES,
                        leaf_header.entries,
                        blocks_needed,
                        extents,
                    )?;
                }
                Ok(())
            }
            _ => Err(Ext4Error::UnsupportedExtent),
        }
    }

    fn read_block(&mut self, block: u64, out: &mut [u8]) -> Result<(), Ext4Error> {
        if out.len() > self.superblock.block_size {
            return Err(Ext4Error::BufferTooSmall);
        }
        let offset = self.block_byte_offset(block);
        self.read_at(offset, out)
    }

    fn read_at(&mut self, offset: u64, out: &mut [u8]) -> Result<(), Ext4Error> {
        read_at(self.device, offset, out)
    }
}

fn read_superblock<D: BlockDevice>(device: &mut D) -> Result<Superblock, Ext4Error> {
    let mut raw = [0u8; SUPERBLOCK_SIZE];
    read_at(device, SUPERBLOCK_OFFSET, &mut raw)?;

    if read_u16(&raw, 56)? != EXT4_MAGIC {
        return Err(Ext4Error::BadMagic);
    }

    let log_block_size = read_u32(&raw, 24)?;
    if log_block_size > 2 {
        return Err(Ext4Error::UnsupportedBlockSize);
    }
    let block_size = 1024usize << log_block_size;
    if block_size > MAX_BLOCK_SIZE || block_size < 1024 {
        return Err(Ext4Error::UnsupportedBlockSize);
    }

    let inode_size = read_u16(&raw, 88)? as usize;
    let blocks_per_group = read_u32(&raw, 32)?;
    let inodes_per_group = read_u32(&raw, 40)?;
    let descriptor_size_raw = read_u16(&raw, 254).unwrap_or(0) as usize;
    let descriptor_size = if descriptor_size_raw == 0 {
        32
    } else {
        descriptor_size_raw
    };

    if inode_size < MIN_INODE_SIZE
        || blocks_per_group == 0
        || inodes_per_group == 0
        || descriptor_size < 32
    {
        return Err(Ext4Error::InvalidSuperblock);
    }

    let group_descriptor_table_offset = if block_size == 1024 {
        2 * block_size as u64
    } else {
        block_size as u64
    };

    Ok(Superblock {
        block_size,
        inode_size,
        blocks_per_group,
        inodes_per_group,
        descriptor_size,
        group_descriptor_table_offset,
    })
}

fn read_at<D: BlockDevice>(device: &mut D, offset: u64, out: &mut [u8]) -> Result<(), Ext4Error> {
    let mut done = 0usize;
    let mut sector = [0u8; SECTOR_SIZE];

    while done < out.len() {
        let absolute = offset
            .checked_add(done as u64)
            .ok_or(Ext4Error::AddressOverflow)?;
        let lba = absolute / SECTOR_SIZE as u64;
        let sector_offset = (absolute % SECTOR_SIZE as u64) as usize;
        let take = min(out.len() - done, SECTOR_SIZE - sector_offset);

        device.read_sector(lba, &mut sector)?;
        out[done..done + take].copy_from_slice(&sector[sector_offset..sector_offset + take]);
        done += take;
    }

    Ok(())
}

