pub struct TrapFrame {
    pub regs: [usize; 32],
    pub era: usize,
    pub prmd: usize,
    pub estat: usize,
    pub badv: usize,
}

impl TrapFrame {
    pub const fn new() -> Self {
        Self {
            regs: [0; 32],
            era: 0,
            prmd: 0,
            estat: 0,
            badv: 0,
        }
    }

    pub fn trap_pc(&self) -> usize {
        self.era
    }

    pub fn trap_cause(&self) -> usize {
        (self.estat >> ESTAT_ECODE_SHIFT) & ESTAT_ECODE_MASK
    }

    pub fn trap_value(&self) -> usize {
        self.badv
    }

    pub fn previous_privilege_is_user(&self) -> bool {
        self.prmd & PRMD_PPLV_MASK == PRMD_PPLV_USER
    }

    /// Force this frame to resume in U-mode (PPLV=PLV3/user). `rt_sigreturn`
    /// restores a TrapFrame from fully user-controlled memory; without this a
    /// forged frame with PPLV=kernel would `ertn` into a privileged ring at a
    /// user-chosen PC (privilege escalation). A legitimate signal frame already
    /// has PPLV=user (the interrupted code was user-mode), so this is a no-op for
    /// real returns.
    pub fn sanitize_user_privilege(&mut self) {
        self.prmd = (self.prmd & !PRMD_PPLV_MASK) | PRMD_PPLV_USER;
    }

    pub fn syscall_args(&self) -> [usize; 6] {
        [
            self.regs[4],
            self.regs[5],
            self.regs[6],
            self.regs[7],
            self.regs[8],
            self.regs[9],
        ]
    }

    pub fn syscall_nr(&self) -> usize {
        self.regs[11]
    }

    pub fn set_syscall_result(&mut self, result: isize) {
        self.regs[4] = result as usize;
    }

    pub fn set_user_stack(&mut self, stack: usize) {
        self.regs[3] = stack;
    }

    /// User program counter (era).
    pub fn program_counter(&self) -> usize {
        self.era
    }

    pub fn set_program_counter(&mut self, pc: usize) {
        self.era = pc;
    }

    /// First argument register (a0) — set to the signal number on delivery.
    pub fn set_arg0(&mut self, value: usize) {
        self.regs[4] = value;
    }

    /// Return-address register (ra) — set to the sa_restorer on delivery so the
    /// handler returns into the rt_sigreturn trampoline.
