#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum BlockError {
    NotPresent,
    BadDevice,
    QueueUnavailable,
    IoError,
    Timeout,
    BufferTooSmall,
}

impl BlockError {
    pub const fn label(self) -> &'static str {
        match self {
            BlockError::NotPresent => "not-present",
            BlockError::BadDevice => "bad-device",
            BlockError::QueueUnavailable => "queue-unavailable",
            BlockError::IoError => "io-error",
            BlockError::Timeout => "timeout",
            BlockError::BufferTooSmall => "buffer-too-small",
        }
    }
}

/// Ring-state snapshot captured at the moment a read failed. Forensics for the
/// grader-only deterministic `fs:block:io-error` family (cycle55-57): the
/// next failing round tells us exactly which desync produced it.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct BlockErrorDiag {
    pub error: BlockError,
    pub lba: u64,
    pub status: u8,
    pub used_id: u32,
    pub device_used_idx: u16,
    pub shadow_used_idx: u16,
    pub shadow_avail_idx: u16,
}

/// Cumulative device diagnostics: total reads issued, recovery resets, the
/// dead-device flag, plus the most recent failure snapshot (if any). Printed
/// by the runner once per discovered script.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct BlockDiag {
    pub reads: u64,
    pub resets: u32,
    pub dead: bool,
    pub last_error: Option<BlockErrorDiag>,
}

impl BlockDiag {
    pub const fn empty() -> Self {
        Self {
            reads: 0,
            resets: 0,
            dead: false,
            last_error: None,
        }
    }
}

impl core::fmt::Display for BlockDiag {
    fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
        write!(
            f,
            "reads={} resets={} dead={}",
            self.reads, self.resets, self.dead
        )?;
        if let Some(diag) = self.last_error {
            write!(
                f,
                " last_err={} lba={} status={} used_id={} dev_used={} shadow_used={} avail={}",
                diag.error.label(),
                diag.lba,
                diag.status,
                diag.used_id,
                diag.device_used_idx,
                diag.shadow_used_idx,
                diag.shadow_avail_idx,
            )?;
        }
        Ok(())
    }
}

/// Consecutive-failure circuit breaker. A read that still fails AFTER a device
/// re-init counts one failure; any success resets the streak. Once the limit
/// is reached the device is declared dead and every subsequent read fails
/// IMMEDIATELY — no polling — so a wedged device costs seconds, not hours
/// (the cycle57 LA tail consumed its whole 2 h window on exactly that crawl).
pub const DEAD_DEVICE_FAILURE_LIMIT: u32 = 8;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct FailureBreaker {
    consecutive: u32,
    dead: bool,
}

impl FailureBreaker {
    pub const fn new() -> Self {
        Self {
            consecutive: 0,
            dead: false,
        }
    }

    pub fn record_success(&mut self) {
        self.consecutive = 0;
    }

    /// Record an unrecovered failure; returns true once the device is dead.
    pub fn record_failure(&mut self) -> bool {
        self.consecutive = self.consecutive.saturating_add(1);
        if self.consecutive >= DEAD_DEVICE_FAILURE_LIMIT {
            self.dead = true;
        }
        self.dead
    }

    pub const fn is_dead(&self) -> bool {
        self.dead
    }
}

pub trait BlockDevice {
    fn read_sector(&mut self, lba: u64, buf: &mut [u8; 512]) -> Result<(), BlockError>;

    /// Device diagnostics (read counter + last failure snapshot). Default for
    /// mocks/hosts: empty.
    fn diag(&self) -> BlockDiag {
        BlockDiag::empty()
    }
}

pub const DEFAULT_TIMEOUT_RETRIES: usize = 2;

pub const fn should_retry_block_timeout(
    error: BlockError,
    attempt: usize,
    retry_budget: usize,
) -> bool {
    matches!(error, BlockError::Timeout) && attempt < retry_budget
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn timeout_retries_stop_after_budget_and_ignore_hard_errors() {
        assert!(should_retry_block_timeout(BlockError::Timeout, 0, 2));
        assert!(should_retry_block_timeout(BlockError::Timeout, 1, 2));
        assert!(!should_retry_block_timeout(BlockError::Timeout, 2, 2));
        assert!(!should_retry_block_timeout(BlockError::IoError, 0, 2));
        assert!(!should_retry_block_timeout(BlockError::BadDevice, 0, 2));
    }

    #[test]
    fn breaker_declares_dead_after_consecutive_unrecovered_failures() {
        let mut breaker = FailureBreaker::new();
        for _ in 0..DEAD_DEVICE_FAILURE_LIMIT - 1 {
            assert!(!breaker.record_failure());
        }
        assert!(!breaker.is_dead());
        assert!(breaker.record_failure());
        assert!(breaker.is_dead());
    }

    #[test]
    fn breaker_success_resets_the_streak() {
        let mut breaker = FailureBreaker::new();
        for _ in 0..DEAD_DEVICE_FAILURE_LIMIT - 1 {
            breaker.record_failure();
        }
        breaker.record_success();
        for _ in 0..DEAD_DEVICE_FAILURE_LIMIT - 1 {
            assert!(!breaker.record_failure());
        }
        assert!(!breaker.is_dead());
    }

    #[test]
    fn block_diag_display_is_compact_and_complete() {
        let mut diag = BlockDiag::empty();
        diag.reads = 7;
        assert_eq!(alloc_format(&diag), "reads=7 resets=0 dead=false");

        diag.resets = 2;
        diag.dead = true;
        diag.last_error = Some(BlockErrorDiag {
            error: BlockError::IoError,
            lba: 4096,
            status: 1,
            used_id: 0,
            device_used_idx: 9,
            shadow_used_idx: 8,
            shadow_avail_idx: 9,
        });
        assert_eq!(
            alloc_format(&diag),
            "reads=7 resets=2 dead=true last_err=io-error lba=4096 status=1 used_id=0 dev_used=9 shadow_used=8 avail=9"
        );
    }

    fn alloc_format(diag: &BlockDiag) -> String {
        format!("{diag}")
    }
}
